  ('social-worker-moex-07660', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '承續Otto Rank正向精神醫學理論觀點的功能學派的基本假定，請問其主要的處遇焦點或做法傾向於儘量 不包括下列那一個選項？', '["治療案主的病理症狀或病態人格", "激發案主改變意志和動力，以及自我的成長與展現", "強調人的整體性、獨特性和平等互惠的專業關係", "強調機構功能和資源的重要性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07661', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就生態觀點的主要理論假定而言，請問其在社會工作實務處遇的策略取向上，並不包括下列那一個選項？', '["個人病態或病理的干預與介入", "個人與環境的調適或互惠", "環境品質改善或個人社區支持網絡重建", "個人在環境中最佳定位或生態位置（niche）的追求"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07662', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '犯罪學理論中的「犯罪古典學派」認為青少年偏差行為產生的原因為何（請選出最適者）？', '["認為犯罪是由事實所決定", "認定自由意志是犯罪主因", "認為是內在心理因素", "認為是社會系統的性質與功能之作用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07663', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下那些對歐美睦鄰運動的發展描述是正確的（請選最完整、最適合的答案）？①英國牧師索里（Solly）', '["美國亞當斯女士（Jane Addams）為美國睦鄰運動先鋒者", "湯恩比館（Toynbee Hall）及 胡爾館（Hull House）都是著名的睦鄰服務中心", "睦鄰運動是由美國開始發展的", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07664', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就開放性的系統觀點而言，請問其理論的基本假定並不包括下列那一個選項？', '["系統雖有一定的範疇或界限，但仍與其他系統維持互動，和保持輸入和輸出的運作", "系統中部分的變動並不致引起其他部分或整體的變動", "系統中的整體乃大於各部分的加總", "系統中各部分之間的運作或互動的目標或結果，可能是殊途同歸（equi-finality）或殊途異歸（multi-finality）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07665', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就理論觀點而言，社會支持網絡對個人遭遇危機事件時，可以產生什麼效應？', '["直接效應（main effect）", "緩衝效應（buffer effect）", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07666', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在處遇目標上，企圖解構文化建構中男性優越意識型態的主張，主要乃屬於女性主義的那一流派觀點？', '["自由派", "激進派", "社會主義派", "後現代派"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07667', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下何者對十九世紀的慈善組織會社（Charity Organization Society, COS）及湯恩比館（Toynbee Hall） 的描述是正確的？', '["慈善組織會社對貧窮的看法是社會歸因", "湯恩比館的發展是由上流社會主導", "慈善組織會社將貧民分為值得幫助與不值得幫助兩類", "湯恩比館濟貧的原則為「教他捕魚，不要給他魚吃」"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07668', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下那一個敘述較符合基變社會工作（Radical Social Work）的特性？', '["基變社會工作會把問題置焦於「障礙」本身，相信人心的障礙來自未知的與內在的條件", "基變社會工作是以「巨視」（macro）或「微視」（micro）作為方法，允許社會工作者選定專精或核心 的實施方法或領域", "基變社會工作是一種專業的信念或意識形態", "基變社會工作是用不同的介入技巧在不同的機構設施中，協助不同的案主群體處理個人與社會問題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07669', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當社會工作者處理家暴婦女時，協助其找到社工員本身所屬機構外的庇護中心，並協助其採取法律途徑 以保障其權益，並更進一步協助其處理子女的照顧，這時社工員主要扮演何種角色？', '["仲介人（broker）", "協商者（negotiator）", "調解者（mediator）", "倡導者（advocate）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
